class {{nama_class}}:
    """Logger that attaches a correlation ID to every log entry.
    Thread-safe: each thread gets its own context via threading.local().
    """
    def __init__(self, name='app', id_key='{{id_key}}'):
        self._logger = logging.getLogger(name)
        self._id_key = id_key
        self._local = threading.local()

    def _get_ctx(self):
        if not hasattr(self._local, 'context'):
            self._local.context = {}
        return self._local.context

    def set_context(self, **kwargs):
        """Set context values for the current thread (e.g. request_id, user_id)."""
        ctx = self._get_ctx()
        ctx.update(kwargs)

    def clear_context(self):
        """Clear all context for current thread."""
        self._local.context = {}

    def new_correlation_id(self):
        """Generate and set a new correlation ID. Returns the ID."""
        cid = str(uuid.uuid4())[:8]
        self.set_context(**{self._id_key: cid})
        return cid

    def _format_msg(self, msg):
        ctx = self._get_ctx()
        if ctx:
            ctx_str = ' '.join('[%s=%s]' % (k, v) for k, v in ctx.items())
            return ctx_str + ' ' + msg
        return msg

    def info(self, msg, *args, **kwargs):
        self._logger.info(self._format_msg(msg), *args, **kwargs)

    def warning(self, msg, *args, **kwargs):
        self._logger.warning(self._format_msg(msg), *args, **kwargs)

    def error(self, msg, *args, **kwargs):
        self._logger.error(self._format_msg(msg), *args, **kwargs)

    def debug(self, msg, *args, **kwargs):
        self._logger.debug(self._format_msg(msg), *args, **kwargs)

    def critical(self, msg, *args, **kwargs):
        self._logger.critical(self._format_msg(msg), *args, **kwargs)

class {{nama_class}}:
    """Simple metrics collector: counters, gauges, and histograms. Thread-safe."""
    def __init__(self):
        self._counters = {}
        self._gauges = {}
        self._histograms = {}
        self._lock = threading.Lock()

    def counter(self, name, value=1):
        """Increment counter by value."""
        with self._lock:
            self._counters[name] = self._counters.get(name, 0) + value

    def get_counter(self, name):
        return self._counters.get(name, 0)

    def gauge(self, name, value):
        """Set gauge to value."""
        with self._lock:
            self._gauges[name] = value

    def get_gauge(self, name):
        return self._gauges.get(name, 0)

    def histogram(self, name, value):
        """Record a value in a histogram."""
        with self._lock:
            if name not in self._histograms:
                self._histograms[name] = []
            self._histograms[name].append(value)

    def get_histogram(self, name):
        with self._lock:
            data = list(self._histograms.get(name, []))
        if not data:
            return {'count': 0, 'min': 0, 'max': 0, 'mean': 0}
        return {
            'count': len(data),
            'min': min(data),
            'max': max(data),
            'mean': sum(data) / len(data),
        }

    def export(self):
        """Export all metrics as a dict."""
        with self._lock:
            return {
                'counters': dict(self._counters),
                'gauges': dict(self._gauges),
                'histograms': {
                    name: {'count': len(vals), 'min': min(vals) if vals else 0, 'max': max(vals) if vals else 0, 'mean': sum(vals)/len(vals) if vals else 0}
                    for name, vals in self._histograms.items()
                },
            }

    def reset(self):
        with self._lock:
            self._counters.clear()
            self._gauges.clear()
            self._histograms.clear()

class {{nama_class}}:
    """Health check aggregator. Register check functions and get overall status."""
    def __init__(self, app_name='app', version='1.0.0'):
        self.app_name = app_name
        self.version = version
        self._checks = {}

    def register(self, name, check_func, critical=True):
        """Register a health check.
        check_func: callable that returns True/False or raises on failure.
        critical: if True, failure makes overall status 'unhealthy'.
        """
        self._checks[name] = {'func': check_func, 'critical': critical}

    def run(self):
        """Run all checks. Returns health status dict."""
        results = {}
        overall_healthy = True
        for name, check in self._checks.items():
            start = time.monotonic()
            try:
                result = check['func']()
                ok = result is not False
                error = None
            except Exception as exc:
                ok = False
                error = str(exc)
            elapsed_ms = round((time.monotonic() - start) * 1000, 2)
            if not ok and check['critical']:
                overall_healthy = False
            results[name] = {
                'status': 'healthy' if ok else 'unhealthy',
                'response_time_ms': elapsed_ms,
                'error': error,
                'critical': check['critical'],
            }
        return {
            'status': 'healthy' if overall_healthy else 'unhealthy',
            'app': self.app_name,
            'version': self.version,
            'timestamp': datetime.datetime.now(datetime.timezone.utc).isoformat(),
            'checks': results,
        }

class {{nama_class}}:
    """Track error counts and rates per time window. Thread-safe."""
    def __init__(self, window_seconds={{window_seconds}}):
        self.window = window_seconds
        self._errors = {}
        self._lock = threading.Lock()

    def record(self, error_type='error', message=''):
        """Record an error event."""
        now = time.time()
        with self._lock:
            if error_type not in self._errors:
                self._errors[error_type] = []
            self._errors[error_type].append({'time': now, 'message': message})
            self._cleanup(error_type, now)

    def _cleanup(self, error_type, now):
        """Remove entries older than window."""
        cutoff = now - self.window
        self._errors[error_type] = [e for e in self._errors[error_type] if e['time'] > cutoff]

    def count(self, error_type='error'):
        """Get error count in current window."""
        now = time.time()
        with self._lock:
            if error_type not in self._errors:
                return 0
            self._cleanup(error_type, now)
            return len(self._errors[error_type])

    def rate(self, error_type='error'):
        """Get error rate (errors per second) in current window."""
        c = self.count(error_type)
        return c / self.window if self.window > 0 else 0

    def total(self):
        """Get total errors across all types."""
        now = time.time()
        with self._lock:
            total = 0
            for et in list(self._errors.keys()):
                self._cleanup(et, now)
                total += len(self._errors[et])
            return total

    def summary(self):
        """Get summary of all error types."""
        now = time.time()
        result = {}
        with self._lock:
            for et in list(self._errors.keys()):
                self._cleanup(et, now)
                result[et] = {'count': len(self._errors[et]), 'rate': len(self._errors[et]) / self.window}
        return result
